var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"대적자라는 존재가 있다네.","JPN":"敵対者という存在がいる。","ENG":"There is a being called the Antagonist.","TWN":"有一個叫敵對者的存在。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계의 의지로부터 선택을 받은 존재지.","JPN":"この世界の意志から選ばれた存在だ。","ENG":"This being is chosen by the will of this world.","TWN":"他是被這個世界的意志所選中的。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대적자……?","JPN":"敵対者……？","ENG":"Antagonist...?","TWN":"敵對者……？"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"쉽게 말해, 마왕으로부터 세계를 구하는 동화 속 용사님이야.","JPN":"わかりやすく言うと、魔王から世界を救うおとぎ話の中の勇者だ。","ENG":"Simply put, the Antagonist is the hero from fairytales who saves the world from the Demon Lord.","TWN":"簡單來說，敵對者就是從魔王手中拯救世界的童話英雄。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"존 스미스라는 이방인을 만난 뒤로 나는 줄곧 대적자라는 존재를 찾아왔네.","JPN":"ジョン・スミスという異邦人に会ってから、私はずっと敵対者という存在を探してきた。","ENG":"After meeting the stranger who goes by John Smith, I have been searching for this Antagonist.","TWN":"自從遇到那名叫約翰·史密斯的異鄉人後，我一直在尋找所謂的敵對者。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"언젠가 우리 세계에 닥쳐 올 위기에 대처하기 위해서.","JPN":"いつか私たちの世界に訪れる危機に備えるために。","ENG":"So that we can prepare for the crisis this world might face one day.","TWN":"為了應對未來可能降臨我們世界的危機。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 탐정인 나에게도 쉬운 일이 아니었어. 그 어떤 단서조차 없었거든.","JPN":"だがそれは、探偵である私にも容易なことではなかった。まったく手がかりがなかったからな。","ENG":"It is no easy task for even a detective like me. There seems to be no clue.","TWN":"這對我這樣偵探來說也不是件容易的事。因為根本沒有任何線索。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 마침내 한 여인을 찾아냈지.","JPN":"だが、やっと一人の女性を探し出した。","ENG":"But then, I finally found a woman.","TWN":"但最終我還是找到了一個女人。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세상에 내가 풀어내지 못하는 수수께끼 같은 건 없으니까.","JPN":"この世界に私が解けない謎など、ないのだから。","ENG":"Because there is no mystery I can't solve in this world.","TWN":"果然，這個世界上沒有我解不開的謎題。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네. 비록 멀리서 바라볼 뿐이지만 항상 응원하고 있어.","JPN":"そのとおりだ。ただ遠くから見守っているだけだが、いつも応援している。","ENG":"Although I saw from afar, I'll always be cheering for you.","TWN":"是的。雖然只能遠遠地看著，但我一直在為你加油。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"팬이니까 말이야, 자네의.","JPN":"ファンだからな、君の。","ENG":"I'm actually a fan of yours.","TWN":"史旺，我是你的粉絲。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……설마.","JPN":"……まさか。","ENG":"...It can't be.","TWN":"……難道。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신이 내 팬을 자처했던 이유가……?","JPN":"あなたが私のファンを名乗った理由って……？","ENG":"Is that why you said that you were my fan...?","TWN":"你自稱是我粉絲的理由是……？"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 역시 망설일 수밖에 없었다네.","JPN":"だが、やはり躊躇うしかなかったんだよ。","ENG":"But I was hesitating.","TWN":"但我依舊心存顧忌。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계의 모든 미지를 상대한다는 건, 그만큼 고독한 일이거든.","JPN":"この世界のすべての未知を相手するということは、すごく孤独な仕事だからな。","ENG":"Tackling all the unknown in this world is a lonely task, after all.","TWN":"面對這個世界的所有未知，實在是件孤獨的事情。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그건 누구보다도 내가 가장 잘 알고 있으니까.","JPN":"それは誰よりも私が一番よく知っている。","ENG":"I should know that better than anyone.","TWN":"因為這件事我比任何人都清楚。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마석을 정제하여 순도 높은 각성제와 배합한 <color=#ffd34c>주사액</color>이라네.","JPN":"魔石を精製して高純度の覚醒剤と調合した<color=#ffd34c>注射液</color>だ。","ENG":"It's a <color=#ffd34c>concoction</color> made of refined Mana Stones and high-purity stimulants.","TWN":"那是將魔石精煉後與高純度興奮劑混合製成的<color=#ffd34c>注射液</color>。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수년 전, 내 오랜 벗이 이곳을 떠나기 전에 만들어 둔 거지.","JPN":"数年前、私の旧友がここを出る前に作っておいたものさ。","ENG":"Years ago, an old friend of mine made it before leaving this place.","TWN":"幾年前，我的一個老友在離開這裡之前製作的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이게 없으면, 이제 정상적인 생활이 불가능하거든.","JPN":"もうこれがないと、正常な暮らしができなくてね。","ENG":"Without it, I'm unable to function normally now.","TWN":"沒有這個，現在就無法正常生活了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금 돌이켜보면 어리석은 판단이었어.","JPN":"今思い返せば、愚かな判断だった。","ENG":"It was a foolish decision looking back at it now.","TWN":"現在回想起來，那是個愚蠢的決定。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네에게 더 많은 걸 알려주고, 더 많은 인연을 쌓게 해야 했어…….","JPN":"君にもっとたくさんのことを教えて、より多くの絆を築かせてあげるべきだったんだ……","ENG":"I should've told you more and built a relationship with you…","TWN":"應該告訴你更多，建立更多的聯繫……"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"망각의 여신에게 미움받는 자네인 만큼, 자네에게 소중한 기억을 남겨줬어야 했어.","JPN":"君は忘却の女神に嫌われているから、君に大切な思い出を残してあげるべきだった。","ENG":"For you are shunned by the goddess of oblivion, I should've left you with precious memories.","TWN":"既然你被遺忘女神所厭惡，我本該為你留下珍貴的記憶。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이런 결말이 올 줄 미리 알았다면…….","JPN":"こんな結末が来るとわかっていたなら……","ENG":"If only I had known it would turn out this way...","TWN":"如果早知道會有這樣的結局……"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그거 알고 있나, 스완?","JPN":"知っているか？　スワン。","ENG":"Did you know, Swan?","TWN":"你知道嗎，史旺？"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"백조는 죽기 전에 단 한 번. 아름답게 운다고 하지.","JPN":"白鳥は死ぬ前にたった一度。美しく鳴くらしい。","ENG":"The bird of the same name is said to let out a single beautiful cry right before its death.","TWN":"據說天鵝在死前會發出它這一生中最淒美動聽的叫聲。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 모리어티 교수는 심야의 살인마를 최후의 걸작으로 삼았지만.","JPN":"マグヌム・オプス。モリアーティ教授は深夜の殺人鬼を最後の傑作にしていたが、","ENG":"Magnum Opus. Professor Moriarty claimed that the Midnight Killer was his final masterpiece.","TWN":"偉大傑作。莫里蒂教授將午夜殺人魔視為他最後的傑作。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계가 남긴 진정한 <color=#ffd34c>최후의 걸작</color>은 바로 자네라네.","JPN":"この世界が残した真の<color=#ffd34c>最後の傑作</color>は君だ。","ENG":"But to this world, the true <color=#ffd34c>final masterpiece</color> is none other than you.","TWN":"但對這個世界來說，它所留下的真正的<color=#ffd34c>最後的傑作</color>，就是你啊。"},"stage":{"bg":"SWANSONG_04","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};